1	/**
2	 * Proxy tRPC sub-router.
3	 *
4	 * Ported from apps/gateway/src/routes/connections.ts (proxy endpoints).
5	 * All procedures use serviceProcedure (JWT auth required).
6	 *
7	 * listEndpoints: Returns the provider's API catalog (strips Zod responseSchema).
8	 * execute: Pure authenticated API proxy with 401-retry pattern.
9	 */
10	import { db } from "@db/app/client";
11	import { gatewayInstallations } from "@db/app/schema";
12	import type { ProviderApi, ProviderDefinition } from "@repo/app-providers";
13	import { getProvider } from "@repo/app-providers";
14	import type { TRPCRouterRecord } from "@trpc/server";
15	import { TRPCError } from "@trpc/server";
16	import { eq } from "@vendor/db";
17	import { z } from "zod";
18	
19	import { providerConfigs } from "../../lib/provider-configs";
20	import {
21	  forceRefreshToken,
22	  getActiveTokenForInstallation,
23	} from "../../lib/token-helpers";
24	import { serviceProcedure } from "../../trpc";
25	
26	// ── Proxy Router ────────────────────────────────────────────────────────────
27	
28	export const proxyRouter = {
29	  /**
30	   * List available API endpoints for a connection's provider.
31	   * Source: GET /connections/:id/proxy/endpoints
32	   *
33	   * Strips responseSchema (Zod types are not JSON-serializable).
34	   */
35	  listEndpoints: serviceProcedure
36	    .input(
37	      z.object({
38	        installationId: z.string(),
39	      })
40	    )
41	    .query(async ({ input }) => {
42	      const installation = await db.query.gatewayInstallations.findFirst({
43	        where: eq(gatewayInstallations.id, input.installationId),
44	      });
45	
46	      if (!installation) {
47	        throw new TRPCError({
48	          code: "NOT_FOUND",
49	          message: "Connection not found",
50	        });
51	      }
52	
53	      const providerDef = getProvider(installation.provider);
54	      if (!providerDef) {
55	        throw new TRPCError({
56	          code: "BAD_REQUEST",
57	          message: "Unknown provider",
58	        });
59	      }
60	
61	      // Strip responseSchema (Zod types are not serializable)
62	      const endpoints: Record<
63	        string,
64	        { method: string; path: string; description: string; timeout?: number }
65	      > = {};
66	      for (const [key, ep] of Object.entries(providerDef.api.endpoints)) {
67	        endpoints[key] = {
68	          method: ep.method,
69	          path: ep.path,
70	          description: ep.description,
71	          ...(ep.timeout ? { timeout: ep.timeout } : {}),
72	        };
73	      }
74	
