43	  if (!/^\d+$/.test(installationId)) {
44	    throw new Error("Invalid GitHub installation ID: must be numeric");
45	  }
46	
47	  const jwt = await createGitHubAppJWT(config);
48	  const response = await fetch(
49	    `https://api.github.com/app/installations/${installationId}/access_tokens`,
