57	        "X-GitHub-Api-Version": "2022-11-28",
58	      },
59	    }
60	  );
61	  if (!response.ok) {
62	    throw new Error(
63	      `GitHub installation token request failed: ${response.status}`
64	    );
65	  }
66	
