1	/**
2	 * Backfill tRPC sub-router.
3	 *
4	 * Ported from apps/backfill/src/routes/trigger.ts and apps/backfill/src/routes/estimate.ts.
5	 * All procedures use serviceProcedure (JWT auth required).
6	 *
7	 * KEY CHANGES vs backfill service:
8	 * - tRPC procedures instead of Hono routes
9	 * - Sends memory/* events instead of backfill/* events
10	 * - Direct DB queries instead of gateway HTTP client for connection lookup
11	 * - Direct provider API calls instead of gw.executeApi() for estimate
12	 */
13	
14	import { db } from "@db/app/client";
15	import { gatewayInstallations, orgIntegrations } from "@db/app/schema";
16	import {
17	  type BackfillContext,
18	  getProvider,
19	  type ProviderApi,
20	  type ProviderDefinition,
21	} from "@repo/app-providers";
22	import {
23	  backfillEstimatePayload,
24	  backfillTriggerPayload,
25	} from "@repo/app-providers/contracts";
26	import type { TRPCRouterRecord } from "@trpc/server";
27	import { TRPCError } from "@trpc/server";
28	import { and, eq } from "@vendor/db";
29	import { z } from "zod";
30	
31	import { inngest } from "../../inngest/client";
32	import { providerConfigs } from "../../lib/provider-configs";
33	import { getActiveTokenForInstallation } from "../../lib/token-helpers";
34	import { serviceProcedure } from "../../trpc";
35	
36	// ── Backfill Router ──────────────────────────────────────────────────────
37	
38	interface Sample {
39	  hasMore: boolean;
40	  resourceId: string;
41	  returnedCount: number;
42	}
43	
44	export const backfillRouter = {
45	  /**
46	   * Trigger a backfill run.
47	   * Sends memory/backfill.run.requested event to Inngest.
48	   * Source: POST /trigger
49	   */
50	  trigger: serviceProcedure
51	    .input(backfillTriggerPayload)
52	    .mutation(async ({ input, ctx: _ctx }) => {
53	      // Verify connection exists and is active via direct DB query
54	      const installationRows = await db
55	        .select()
56	        .from(gatewayInstallations)
57	        .where(eq(gatewayInstallations.id, input.installationId))
58	        .limit(1);
59	
60	      const installation = installationRows[0];
61	      if (!installation) {
62	        throw new TRPCError({
63	          code: "NOT_FOUND",
64	          message: "Connection not found",
65	        });
66	      }
67	
68	      if (installation.status !== "active") {
69	        throw new TRPCError({
70	          code: "BAD_REQUEST",
71	          message: `Connection not active (status: ${installation.status})`,
72	        });
73	      }
74	
75	      // Tenant isolation
76	      if (installation.orgId !== input.orgId) {
77	        throw new TRPCError({
78	          code: "FORBIDDEN",
79	          message: "org_mismatch",
80	        });
81	      }
82	
83	      try {
84	        await inngest.send({
85	          name: "memory/backfill.run.requested",
86	          data: {
87	            installationId: input.installationId,
88	            provider: input.provider,
89	            orgId: input.orgId,
90	            depth: input.depth,
91	            entityTypes: input.entityTypes,
92	            holdForReplay: input.holdForReplay,
93	            correlationId: input.correlationId,
94	          },
95	        });
96	      } catch (err) {
97	        throw new TRPCError({
98	          code: "INTERNAL_SERVER_ERROR",
99	          message: `Failed to enqueue backfill: ${err instanceof Error ? err.message : String(err)}`,
100	        });
101	      }
102	
103	      return { status: "accepted", installationId: input.installationId };
104	    }),
105	
106	  /**
107	   * Cancel a running backfill.
108	   * Sends memory/backfill.run.cancelled event to Inngest.
109	   * Source: POST /trigger/cancel
110	   */
111	  cancel: serviceProcedure
112	    .input(
113	      z.object({
114	        installationId: z.string().min(1),
115	        correlationId: z.string().max(128).optional(),
116	      })
117	    )
118	    .mutation(async ({ input }) => {
119	      // Verify installation exists
120	      const installationRows = await db
121	        .select({ id: gatewayInstallations.id })
122	        .from(gatewayInstallations)
123	        .where(eq(gatewayInstallations.id, input.installationId))
124	        .limit(1);
125	
126	      if (!installationRows[0]) {
127	        throw new TRPCError({
128	          code: "NOT_FOUND",
129	          message: "Connection not found",
130	        });
131	      }
132	
133	      try {
134	        await inngest.send({
135	          name: "memory/backfill.run.cancelled",
136	          data: {
137	            installationId: input.installationId,
138	            correlationId: input.correlationId,
139	          },
140	        });
141	      } catch (err) {
142	        throw new TRPCError({
143	          code: "INTERNAL_SERVER_ERROR",
144	          message: `Failed to enqueue cancellation: ${err instanceof Error ? err.message : String(err)}`,
145	        });
146	      }
147	
148	      return { status: "cancelled", installationId: input.installationId };
149	    }),
150	
151	  /**
152	   * Estimate backfill scope by probing provider API page 1 for each resource x entityType.
153	   * Source: POST /estimate
154	   *
155	   * Uses direct provider API calls instead of gw.executeApi().
156	   */
157	  estimate: serviceProcedure
158	    .input(backfillEstimatePayload)
159	    .query(async ({ input }) => {
160	      const { installationId, provider, depth, entityTypes, orgId } = input;
161	
162	      // Fetch connection from DB
163	      const installationRows = await db
164	        .select()
165	        .from(gatewayInstallations)
166	        .where(eq(gatewayInstallations.id, installationId))
167	        .limit(1);
168	
169	      const installation = installationRows[0];
170	      if (!installation) {
171	        throw new TRPCError({
172	          code: "NOT_FOUND",
173	          message: "Connection not found",
174	        });
175	      }
176	
177	      // Tenant isolation
178	      if (installation.orgId !== orgId) {
179	        throw new TRPCError({
