1	import { db } from "@db/app/client";
2	import { gatewayTokens } from "@db/app/schema";
3	import type { OAuthTokens } from "@repo/app-providers";
4	import { encrypt } from "@repo/lib";
5	import { eq } from "@vendor/db";
6	import { getEncryptionKey } from "./encryption";
7	
8	/**
9	 * Write an encrypted token record for an installation.
10	 * Used after OAuth code exchange.
11	 */
12	export async function writeTokenRecord(
13	  installationId: string,
14	  oauthTokens: OAuthTokens
15	): Promise<void> {
16	  const encryptedAccess = await encrypt(
17	    oauthTokens.accessToken,
18	    getEncryptionKey()
19	  );
20	  const encryptedRefresh = oauthTokens.refreshToken
21	    ? await encrypt(oauthTokens.refreshToken, getEncryptionKey())
22	    : null;
23	
24	  const expiresAt = oauthTokens.expiresIn
25	    ? new Date(Date.now() + oauthTokens.expiresIn * 1000).toISOString()
26	    : null;
27	
28	  await db
29	    .insert(gatewayTokens)
30	    .values({
31	      installationId,
32	      accessToken: encryptedAccess,
33	      refreshToken: encryptedRefresh,
34	      expiresAt,
35	      tokenType: oauthTokens.tokenType,
36	      scope: oauthTokens.scope,
37	    })
38	    .onConflictDoUpdate({
39	      target: gatewayTokens.installationId,
40	      set: {
41	        accessToken: encryptedAccess,
42	        refreshToken: encryptedRefresh,
43	        expiresAt,
44	        tokenType: oauthTokens.tokenType,
45	        scope: oauthTokens.scope,
46	        updatedAt: new Date().toISOString(),
47	      },
48	    });
49	}
50	
51	/** Minimum base64-decoded byte length for a valid AES-GCM encrypted value (12-byte IV + 16-byte tag). */
52	const MIN_ENCRYPTED_BYTES = 28;
53	
54	/**
55	 * Best-effort check that `value` looks like an AES-GCM ciphertext (base64, >= {@link MIN_ENCRYPTED_BYTES} decoded bytes).
56	 * This is a heuristic — it can admit some plaintext that happens to be valid base64 of sufficient length.
57	 * For stricter validation consider a versioned prefix or non-printable-byte heuristic.
58	 */
59	function assertEncryptedFormat(value: string): void {
60	  try {
61	    const decoded = atob(value);
62	    if (decoded.length < MIN_ENCRYPTED_BYTES) {
63	      throw new Error("too short");
64	    }
65	  } catch (e) {
66	    const reason = e instanceof Error ? e.message : String(e);
67	    throw new Error(
68	      `existingEncryptedRefreshToken does not appear to be an encrypted value — refusing to persist potentially plaintext token (${reason})`
69	    );
70	  }
71	}
72	
73	/**
74	 * Update an existing token record after refresh.
75	 *
76	 * @param existingEncryptedRefreshToken - The already-encrypted refresh token from the DB.
77	 *   Must be the raw encrypted (base64) value as stored; never pass a plaintext token.
78	 */
79	export async function updateTokenRecord(
80	  tokenId: string,
81	  oauthTokens: OAuthTokens,
82	  existingEncryptedRefreshToken: string | null,
83	  existingExpiresAt: string | null
84	): Promise<void> {
85	  const encryptedAccess = await encrypt(
86	    oauthTokens.accessToken,
87	    getEncryptionKey()
88	  );
89	
90	  let newEncryptedRefresh: string | null;
91	  if (oauthTokens.refreshToken) {
92	    newEncryptedRefresh = await encrypt(
93	      oauthTokens.refreshToken,
94	      getEncryptionKey()
95	    );
96	  } else if (existingEncryptedRefreshToken) {
97	    assertEncryptedFormat(existingEncryptedRefreshToken);
98	    newEncryptedRefresh = existingEncryptedRefreshToken;
99	  } else {
100	    newEncryptedRefresh = null;
101	  }
102	
103	  const newExpiresAt = oauthTokens.expiresIn
104	    ? new Date(Date.now() + oauthTokens.expiresIn * 1000).toISOString()
105	    : existingExpiresAt;
106	
107	  await db
108	    .update(gatewayTokens)
109	    .set({
110	      accessToken: encryptedAccess,
111	      refreshToken: newEncryptedRefresh,
112	      expiresAt: newExpiresAt,
113	      updatedAt: new Date().toISOString(),
114	    })
115	    .where(eq(gatewayTokens.id, tokenId));
116	}
