1	/**
2	 * Delivery recovery cron function
3	 *
4	 * Replaces QStash-scheduled POST /admin/recovery/cron in the relay service.
5	 * Source logic: apps/relay/src/lib/replay.ts + apps/relay/src/routes/admin.ts (lines 224-249)
6	 *
7	 * Sweeps all deliveries stuck in status='received' for more than 5 minutes
8	 * across all providers and installations, then sends memory/webhook.received
9	 * events for each one instead of re-triggering Upstash Workflows.
10	 */
11	
12	import { db } from "@db/app/client";
