1	import { db } from "@db/app/client";
2	import { gatewayTokens } from "@db/app/schema";
3	import type { OAuthTokens } from "@repo/app-providers";
4	import { encrypt } from "@repo/lib";
5	import { eq } from "@vendor/db";
6	import { log } from "@vendor/observability/log/next";
7	import { getEncryptionKey } from "./encryption";
8	
9	/**
10	 * Write an encrypted token record for an installation.
11	 * Used after OAuth code exchange.
12	 */
13	export async function writeTokenRecord(
14	  installationId: string,
15	  oauthTokens: OAuthTokens
16	): Promise<void> {
17	  const encryptedAccess = await encrypt(
18	    oauthTokens.accessToken,
19	    getEncryptionKey()
20	  );
21	  const encryptedRefresh = oauthTokens.refreshToken
22	    ? await encrypt(oauthTokens.refreshToken, getEncryptionKey())
23	    : null;
24	
25	  const expiresAt = oauthTokens.expiresIn
26	    ? new Date(Date.now() + oauthTokens.expiresIn * 1000).toISOString()
27	    : null;
28	
29	  await db
30	    .insert(gatewayTokens)
31	    .values({
32	      installationId,
33	      accessToken: encryptedAccess,
34	      refreshToken: encryptedRefresh,
35	      expiresAt,
36	      tokenType: oauthTokens.tokenType,
37	      scope: oauthTokens.scope,
38	    })
39	    .onConflictDoUpdate({
40	      target: gatewayTokens.installationId,
41	      set: {
42	        accessToken: encryptedAccess,
43	        refreshToken: encryptedRefresh,
44	        expiresAt,
45	        tokenType: oauthTokens.tokenType,
46	        scope: oauthTokens.scope,
47	        updatedAt: new Date().toISOString(),
48	      },
49	    });
50	
51	  log.info("[token-store] token record written", {
52	    installationId,
53	    hasRefreshToken: !!oauthTokens.refreshToken,
54	    hasExpiry: !!oauthTokens.expiresIn,
55	  });
56	}
57	
58	/** Minimum base64-decoded byte length for a valid AES-GCM encrypted value (12-byte IV + 16-byte tag). */
59	const MIN_ENCRYPTED_BYTES = 28;
60	
61	/**
62	 * Best-effort check that `value` looks like an AES-GCM ciphertext (base64, >= {@link MIN_ENCRYPTED_BYTES} decoded bytes).
63	 * This is a heuristic — it can admit some plaintext that happens to be valid base64 of sufficient length.
64	 * For stricter validation consider a versioned prefix or non-printable-byte heuristic.
65	 */
66	function assertEncryptedFormat(value: string): void {
67	  try {
68	    const decoded = atob(value);
69	    if (decoded.length < MIN_ENCRYPTED_BYTES) {
70	      throw new Error("too short");
71	    }
72	  } catch (e) {
73	    const reason = e instanceof Error ? e.message : String(e);
74	    throw new Error(
75	      `existingEncryptedRefreshToken does not appear to be an encrypted value — refusing to persist potentially plaintext token (${reason})`
76	    );
77	  }
78	}
79	
80	/**
81	 * Update an existing token record after refresh.
82	 *
83	 * @param existingEncryptedRefreshToken - The already-encrypted refresh token from the DB.
84	 *   Must be the raw encrypted (base64) value as stored; never pass a plaintext token.
85	 */
86	export async function updateTokenRecord(
87	  tokenId: string,
88	  oauthTokens: OAuthTokens,
89	  existingEncryptedRefreshToken: string | null,
90	  existingExpiresAt: string | null
91	): Promise<void> {
92	  const encryptedAccess = await encrypt(
93	    oauthTokens.accessToken,
94	    getEncryptionKey()
95	  );
96	
97	  let newEncryptedRefresh: string | null;
98	  if (oauthTokens.refreshToken) {
99	    newEncryptedRefresh = await encrypt(
100	      oauthTokens.refreshToken,
101	      getEncryptionKey()
102	    );
103	  } else if (existingEncryptedRefreshToken) {
104	    assertEncryptedFormat(existingEncryptedRefreshToken);
105	    newEncryptedRefresh = existingEncryptedRefreshToken;
106	  } else {
