1	/**
2	 * Delivery recovery cron function
3	 *
4	 * Replaces QStash-scheduled POST /admin/recovery/cron in the relay service.
5	 * Source logic: apps/relay/src/lib/replay.ts + apps/relay/src/routes/admin.ts (lines 224-249)
6	 *
7	 * Sweeps all deliveries stuck in status='received' for more than 5 minutes
8	 * across all providers and installations, then sends memory/webhook.received
9	 * events for each one instead of re-triggering Upstash Workflows.
10	 */
11	
12	import { db } from "@db/app/client";
13	import { gatewayInstallations, gatewayWebhookDeliveries } from "@db/app/schema";
14	import type { SourceType } from "@repo/app-providers";
15	import { getProvider, isWebhookProvider } from "@repo/app-providers";
16	import { and, eq, lt } from "@vendor/db";
17	import { log } from "@vendor/observability/log/next";
18	import { inngest } from "../client";
19	
20	export const deliveryRecovery = inngest.createFunction(
21	  {
22	    id: "memory/delivery.recovery",
23	    name: "Delivery Recovery (5m cron)",
24	    retries: 1,
25	    concurrency: [{ limit: 1 }],
26	  },
27	  { cron: "*/5 * * * *" },
28	  async ({ step }) => {
29	    const BATCH_SIZE = 100;
30	    const STALE_THRESHOLD_MS = 5 * 60 * 1000; // 5 minutes
31	
32	    // -- Step 1: Find stuck deliveries --------------------------------------
33	    const deliveries = await step.run("find-stuck-deliveries", async () => {
34	      const staleBeforeIso = new Date(
35	        Date.now() - STALE_THRESHOLD_MS
36	      ).toISOString();
37	
38	      return db
39	        .select()
40	        .from(gatewayWebhookDeliveries)
41	        .where(
42	          and(
43	            eq(gatewayWebhookDeliveries.status, "received"),
44	            lt(gatewayWebhookDeliveries.receivedAt, staleBeforeIso)
45	          )
46	        )
47	        .orderBy(gatewayWebhookDeliveries.receivedAt)
48	        .limit(BATCH_SIZE);
49	    });
50	
51	    if (deliveries.length === 0) {
52	      return { replayed: 0, skipped: 0, failed: 0 };
53	    }
54	
55	    log.info("[delivery-recovery] found stuck deliveries", {
56	      count: deliveries.length,
57	    });
58	
59	    // -- Step 2: Re-send each as memory/webhook.received --------------------
60	    const result = await step.run("replay-deliveries", async () => {
61	      const replayed: string[] = [];
62	      const skipped: string[] = [];
63	      const failed: string[] = [];
64	
65	      for (const delivery of deliveries) {
66	        if (!delivery.payload) {
67	          skipped.push(delivery.deliveryId);
68	          continue;
69	        }
70	
71	        try {
72	          const parsedPayload = JSON.parse(delivery.payload) as unknown;
73	          const providerName = delivery.provider as SourceType;
74	
75	          // Re-extract resourceId from stored payload via provider
76	          let resourceId: string | null = null;
77	          try {
78	            const providerDef = getProvider(providerName);
79	            if (providerDef && isWebhookProvider(providerDef)) {
80	              resourceId =
81	                providerDef.webhook.extractResourceId(parsedPayload) ?? null;
82	            }
83	          } catch {
84	            // If extraction fails, proceed with null — ingest delivery handles it
85	          }
86	
87	          // Resolve connection info for preResolved if installationId is available
88	          let preResolved: { connectionId: string; orgId: string } | undefined;
89	          if (delivery.installationId) {
90	            // Look up orgId from installation
91	            const installationRows = await db
92	              .select({ orgId: gatewayInstallations.orgId })
93	              .from(gatewayInstallations)
94	              .where(eq(gatewayInstallations.id, delivery.installationId))
95	              .limit(1);
96	
97	            if (installationRows[0]?.orgId) {
98	              preResolved = {
99	                connectionId: delivery.installationId,
100	                orgId: installationRows[0].orgId,
101	              };
102	            }
103	          }
104	
105	          // Send as Inngest event instead of Upstash Workflow trigger
106	          await inngest.send({
107	            name: "memory/webhook.received",
108	            data: {
109	              provider: providerName,
110	              deliveryId: delivery.deliveryId,
111	              eventType: delivery.eventType,
112	              resourceId,
113	              payload: parsedPayload,
114	              receivedAt: new Date(delivery.receivedAt).getTime(),
115	              ...(preResolved ? { preResolved } : {}),
116	            },
117	          });
118	
119	          replayed.push(delivery.deliveryId);
120	
121	          // Reset status — ingest delivery will advance to processed
122	          try {
123	            await db
124	              .update(gatewayWebhookDeliveries)
125	              .set({ status: "received" })
126	              .where(
127	                and(
128	                  eq(gatewayWebhookDeliveries.provider, delivery.provider),
129	                  eq(gatewayWebhookDeliveries.deliveryId, delivery.deliveryId)
130	                )
131	              );
132	          } catch (err) {
133	            log.error("[delivery-recovery] DB status update failed", {
134	              deliveryId: delivery.deliveryId,
135	              error: err,
136	            });
137	          }
138	        } catch {
139	          failed.push(delivery.deliveryId);
140	        }
141	      }
142	
143	      return { replayed, skipped, failed };
144	    });
145	
146	    log.info("[delivery-recovery] complete", {
147	      replayed: result.replayed.length,
148	      skipped: result.skipped.length,
149	      failed: result.failed.length,
150	    });
151	
152	    return {
153	      replayed: result.replayed.length,
154	      skipped: result.skipped.length,
155	      failed: result.failed.length,
156	    };
