34	
35	export const connectionsRouter = {
36	  /**
37	   * List installations, optionally filtered by status.
38	   * Source: GET /connections
39	   */
40	  list: serviceProcedure
41	    .input(
42	      z.object({
43	        orgId: z.string(),
44	        status: z.string().optional(),
45	      })
46	    )
